select sc.id, sc.post_id as postId, sc.publish_id as publishId, sc.content, sc.created_time as createdTime, u.nickname as publishName, u.avatar as publishAvatar from space_comment sc left join user u on sc.publish_id = u.id where sc.post_id in
#{postId}
and sc.status = 0 order by sc.created_time asc
